SELECT ?athlete (COUNT(?event) AS ?number_of_events)
WHERE {
  wd:Q13328244 wdt:P255 ?event.
  ?medal wdt:P159 ?event;
         wdt:P128 wd:Q21;
         wdt:P193 wd:Q55036;
         wdt:P1346 ?athlete.
  ?athlete wdt:P19 ?birthplace.
  ?birthplace wdt:P131 wd:Q884339.
  ?birthplace rdfs:label ?birthplaceLabel.
  FILTER (LCASE(?birthplaceLabel) = "barsar")
}
GROUP BY ?athlete

SELECT (COUNT(DISTINCT ?event) AS ?number_of_events)
WHERE {
  ?athlete wdt:P19 ?birthplace.
  ?birthplace rdfs:label ?birthplaceLabel.
  FILTER (LCASE(?birthplaceLabel) = "barsar")
  ?birthplace wdt:P131 wd:Q55036.
  ?athlete wdt:P128 wd:Q21.
  ?medal wdt:P128 wd:Q21;
         wdt:P255 wd:Q6255;
         wdt:P155 ?event;
         wdt:P162 wd:Q551655.
}

